finalProject.cssTemplate:
html, body {
  height: 100%;
  margin: 0;
}

body {
  display: flex;
  align-items: center;
  justify-content: center;
  background: #f5f4f0;
  font-family: system-ui, -apple-system, sans-serif;
  color: #1A1E2E;
}

#box {
  width: 400px;
  height: 220px;
  border-radius: 12px;
  background: #e5e5ea;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: 6px;
  cursor: pointer;
  user-select: none;
  transition: background 120ms ease, color 120ms ease;
}

#big {
  font-size: 28px;
  font-weight: 600;
}

#small {
  font-size: 14px;
  color: #6b7280;
}

#box.ready {
  background: #059669;
  color: #ffffff;
}
#box.ready #small {
  color: rgba(255, 255, 255, 0.85);
}

#box.early {
  background: #DC2626;
  color: #ffffff;
}
#box.early #small {
  color: rgba(255, 255, 255, 0.85);
}

